/// <summary>
/// Extend active method to enable subcontrcting prodIds - Abhinav  
/// </summary>
[ExtensionOf(formDataSourceStr(ProdTable,ProdTable))]
final class ETGProdTable_ProdTableDS_Extension
{
}

Method.Source:
public int active()
{
    int ret;
    ret =  next active();

    ProdTable ProdTable = this.cursor();
    FormControl ETGSubcontractingprodIds = element.design().controlName(formControlStr(ProdTable, ETGSubcontractingprodIds));
    ETGSubcontractingprodIds.visible(ETGCanadaParameters::find().EnableSubContractingPO || ProdTable.ETGChildProdId);

    FormControl Actions = element.design().controlName(formControlStr(ProdTable,Actions));
    Actions.enabled(!ProdTable.ETGChildProdId);

    this.allowDelete(!ProdTable.ETGChildProdId);

    //CS - BIN Qty Status activation - Abhinav
    FormRun formRun = this.formRun();
    FormPartControl formpartcontrol = formRun.design().controlName("ETGBinQtyAvailable");
    formpartcontrol.visible(ETGCanadaParameters::find().EnableBinQtyStatus);

    if(ETGCanadaParameters::find().EnableBinQtyStatus)
    {
        InventDim inventdim = ProdTable.inventDim();
        ETGBinQtyVisualChartHelperClass::populateBinQtyChartData(inventdim,formpartcontrol);
    }
    //CE

    return ret;
}
